parameters.jsCode:
// Rotate through post types to keep content varied
const postTypes = [
  { type: 'tip', prompt: 'Write a helpful Facebook post for Tampa Bay homeowners about hurricane window preparation. Be genuinely helpful. 3-4 sentences. Conversational tone. End with a soft CTA to comment if they have questions. No hashtags yet.' },
  { type: 'savings', prompt: 'Write a helpful Facebook post for Tampa Bay homeowners about how energy efficient windows can lower electric bills in Florida heat. Mention specific savings (15-30%). 3-4 sentences. Include a question to drive comments.' },
  { type: 'seasonal', prompt: 'Write a timely Facebook post for Tampa Bay homeowners about preparing windows for hurricane season. Practical tips. 3-4 sentences. Friendly tone.' },
  { type: 'faq', prompt: 'Write a Facebook post answering a common question Tampa Bay homeowners have about window replacement — either about permits, cost, timeline, or insurance discounts. Educational tone. 3-4 sentences.' },
  { type: 'social_proof', prompt: 'Write a Facebook post in the voice of a satisfied Tampa Bay homeowner who just got new windows. First person, authentic, mentions specific benefit (cooler home, lower bill, peace of mind in storms). 3-4 sentences. No fake names.' },
  { type: 'before_after', prompt: 'Write a Facebook post describing the transformation of a Tampa Bay home after window replacement — drafty old windows to new energy efficient ones. Paint a picture. 3-4 sentences. Encouraging tone.' }
];

const today = new Date().getDay(); // 0-6
const postType = postTypes[today % postTypes.length];

// Hashtags to append
const hashtags = [
  '#TampaBay #HomeImprovement #Windows',
  '#Tampa #HurricanePrep #FloridaHome',
  '#StPete #HomeUpgrade #EnergyEfficient',
  '#TampaBayArea #WindowReplacement #FloridaLiving',
  '#Clearwater #HurricaneWindows #HomeOwner'
];
const tagSet = hashtags[Math.floor(Math.random() * hashtags.length)];

return [{ json: { ...postType, hashtags: tagSet, date: new Date().toLocaleDateString() } }];

