const response = $input.first().json;
const meta = $('Pick Post Type').first().json;
const postText = response.choices[0].message.content.trim();
const fullPost = `${postText}\n\n${meta.hashtags}`;

return [{
  json: {
    type: meta.type,
    date: meta.date,
    post: fullPost,
    char_count: fullPost.length,
    ready: true
  }
}];
